// n8n Code node (Run Once for All Items) - aggregate OCR text from PDF pages

let aggregatedText = '';
const pageTexts = [];

// helper: safely extract page text from a single page response
function extractPageText(page) {
  // Most common for Vision OCR:
  // - page.fullTextAnnotation.text
  // Fallback:
  // - page.textAnnotations[0].description
  if (page?.fullTextAnnotation?.text) return page.fullTextAnnotation.text;
  if (Array.isArray(page?.textAnnotations) && page.textAnnotations[0]?.description) {
    return page.textAnnotations[0].description;
  }
  return '';
}

// This handles two common shapes:
// A) Each input item is a "page" item: item.json.responses[0] is the page response
// B) One item contains multiple pages: item.json.responses[0].responses is an array of pages

let pageCounter = 0;

for (const item of $input.all()) {
  // Case B: nested pages array
  const nestedPages = item?.json?.responses?.[0]?.responses;
  if (Array.isArray(nestedPages)) {
    for (const page of nestedPages) {
      const pageText = extractPageText(page);
      if (pageText.trim()) {
        pageCounter += 1;
        pageTexts.push({ pageNumber: pageCounter, text: pageText });
        aggregatedText += pageText.trim() + '\n\n';
      }
    }
    continue;
  }

  // Case A: page response is directly at responses[0] (or sometimes in item.json.responses)
  const directPage =
    item?.json?.responses?.[0] ??
    item?.json?.responses ??
    item?.json;

  const pageText = extractPageText(directPage);
  if (pageText.trim()) {
    pageCounter += 1;
    pageTexts.push({ pageNumber: pageCounter, text: pageText });
    aggregatedText += pageText.trim() + '\n\n';
  }
}

// Final cleanup
aggregatedText = aggregatedText.trim();

return [
  {
    json: {
      aggregatedText,
      totalPages: pageTexts.length,
      pages: pageTexts
    }
  }
];

